import { useState } from "react"

function CanvasContainer({ canvas, setDoubleClickedObj }) {
    const { canvasRef, objects, startDragging, dragging, stopDragging } =
        canvas;

    return (
        <div
            className="canvas-container"
            ref={canvasRef}
            onMouseMove={dragging}
            onMouseUp={stopDragging}
            style={{ position: 'relative' }}
        >
            {objects.map((obj) => (
                <div
                    key={obj.id}
                    className="obj"
                    onMouseDown={(e) => startDragging(obj.id, e)}
                    onDoubleClick={(e) => setDoubleClickedObj(e.target.key)}
                    style={{
                        position: 'absolute',
                        left: obj.left,
                        top: obj.top,
                    }}
                />
            ))}
        </div>
    );
}

export default CanvasContainer;
